import React,{useEffect,useState}from"react";import{FileText,ShieldCheck,UploadCloud}from"lucide-react";import{authAPI}from"../../services/api.js";import{useToast}from"../../components/ui/Toast.jsx";import{CardPanel,DetailsGrid,PageHeader,StatusPill}from"../../components/ui/PortalUI.jsx";
export default function VendorDocumentsPage(){const{showToast}=useToast();const[profile,setProfile]=useState(null);useEffect(()=>{(async()=>{try{setProfile(await authAPI.profile("vendor"))}catch(e){showToast(e.message,"error")}})()},[]);return <div className="page-wrap"><PageHeader icon={FileText} title="Documents" subtitle="Upload and manage your verification documents."/><CardPanel title="Documents" subtitle="Company docs, compliance and insurance."><div className="table-scroll"><table><thead><tr><th>Document Name</th><th>Type</th><th>Uploaded On</th><th>Status</th><th>Action</th></tr></thead><tbody>{[["Public Liability Insurance","Insurance"],["Goods in Transit Insurance","Insurance"],["Company Registration","Company"],["VAT Certificate","Company"],["ID Proof","Compliance"]].map((d,i)=><tr key={d[0]}><td><b>{d[0]}</b></td><td>{d[1]}</td><td>10 Jun 2025</td><td><StatusPill value={profile?.verification_status||"verified"}/></td><td><button className="tiny-btn"><UploadCloud size={13}/>Upload</button></td></tr>)}</tbody></table></div><div style={{marginTop:14}}><DetailsGrid rows={[["Company Registration",profile?.company_registration_number],["VAT Number",profile?.vat_number],["Insurance",profile?.insurance_details],["Verification",profile?.verification_status],["Status",profile?.status]]}/></div></CardPanel></div>}
